import{_ as e,o,c as l,f as i}from"./app-19f36e20.js";const c={},a=i('<h1 id="搞清楚碰撞形状是什么" tabindex="-1"><a class="header-anchor" href="#搞清楚碰撞形状是什么" aria-hidden="true">#</a> 搞清楚碰撞形状是什么？</h1><p>在 Godot 中，物理学主要基于物体(Body)和<strong>碰撞形状(Shape)</strong>。其中，形状（Shape）是物体的几何形状或碰撞体积。在物理仿真中，形状<strong>用于检测物体之间的碰撞</strong>。形状可以是简单的几何体，如盒子、球体、胶囊体，也可以是复杂的自定义形状。</p><p>总之，物体的形状可以与其他物体的形状进行交互，从而触发碰撞事件。形状还可以用于确定物体的边界和碰撞区域，以便进行精确的碰撞检测和响应。</p><p>如果你要定义碰撞形状的话，可以试试以下碰撞形状节点：</p><ul><li><p><code>CollisionShape2D</code> 定义 2D 空间中的碰撞形状。</p><ul><li>shape 属性 <ul><li><code>CapsuleShape</code> 胶囊形状</li><li><code>CircleShape</code> 圆形形状</li><li><code>ConvexPolygonShape</code> 凸多边形形状</li><li><code>RectangleShape</code> 矩形形状</li><li><code>TriangleShape</code> 三角形形状</li></ul></li><li>OneWayCollision（单向碰撞）： 允许物体只能在一个方向上与其他物体发生碰撞。</li></ul></li><li><p><code>CollisionPolygon2D</code> 定义 2D 碰撞多边形。</p></li></ul><div class="custom-container danger"><p class="custom-container-title">注意事项</p><p>需要注意的是：该碰撞节点必须是物理体（physics body）节点的直接子节点。</p></div><div class="custom-container tip"><p class="custom-container-title">个人经验</p><p>一般来说，定义碰撞形状时不需要像素完美。形状越简单，性能越好，最终玩家可能不会注意到。例如，无论是在2D还是3D中，<code>CapsuleShape（胶囊形状）</code>都非常适合角色。</p></div>',7),s=[a];function t(n,p){return o(),l("div",null,s)}const r=e(c,[["render",t],["__file","collision-shape.html.vue"]]);export{r as default};
